update orders
cancel_reason=#{cancelReason}, rejection_reason=#{rejectionReason}, cancel_time=#{cancelTime}, pay_status=#{payStatus}, pay_method=#{payMethod}, checkout_time=#{checkoutTime}, status = #{status}, delivery_time = #{deliveryTime}
where id = #{id}

mapper.select:
select * from orders 
        and user_id = #{userId}
        and status = #{status}

select * from orders

    and number = #{number}
    and phone = #{phone}
    and begin_time = #{beginTime}
    and end_time = #{endTime}
    and user_id = #{userId}
    and status = #{status}

select sum(amount) from orders

    and order_time > #{begin} 
    and order_time < #{end} 
    and status = #{status}

SELECT DATE(order_time) AS date, IFNULL(SUM(amount), 0) AS turnover FROM orders
AND order_time > CONCAT(#{begin}, ' 00:00:00') AND order_time < CONCAT(#{end}, ' 23:59:59') AND status = #{status}
GROUP BY DATE(order_time) ORDER BY date

SELECT DATE(order_time) AS date, IFNULL(count(id), 0) AS turnover FROM orders
AND order_time > CONCAT(#{begin}, ' 00:00:00') AND order_time < CONCAT(#{end}, ' 23:59:59') AND status = #{status}
GROUP BY DATE(order_time) ORDER BY date

select count(id)
from orders


        and order_time > #{begin}


        and order_time < #{end}


        and status = #{status}
